insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2017-12-27','Correo-e del CRR de Mérida. Les informamos que la noche de navidad Concha ha sido ingresada en el Hospital Infanta Cristina, por un cuadro respiratorio. En el día de hoy hablé con una de sus hermanas y me comenta que presenta infección en un pulmón y que le han puesto una vía intravenosa para el tratamiento. Cualquier novedad se les comunicará. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-12-28','(Pedro)Conversación con la Dra. Mª Victoria Carrasco Roncero, Médico de Familia del C.Salud de Aldea Moret (927-235141). Valentina está de vacaciones esta semana. +++La llamada coincide con la presencia de Dª Paula en la consulta de Enfermería, donde ha acudido a curarse la herida que tiene en el codo. +++La Médico comenta que ella no la conoce demasiado porque lleva el caso desde hace poco tiempo (remitió Informe de 21 de diciembre). +++Ella no la ve mal para tener la necsidad de ingresarla nuevamente en UHB. Hablará con ella y si considera necesario el ingreso en la Unidad activará el 112. Si no es preciso, hablará con Valentina la próxima semana sobre la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2017-12-28','(Pedro) Conversación con Cintia, T. Soc. de "Vera". +++José Mª pasó la Noche Buena en su casa y regresó a "Vera" el día 26 de diciembre. +++La situación parace estra más tranquila en cuenato al comportamineto de José Mª. Los incidentes protagonizados también fueron puestos en conocimineto del S. Territorial. +++Confirmará que la madre de José Mª llevará a su hijo a la cita del 19 de ENERO a las 11:00h en el CADEx de Cáceres. +++Si no pudiera, le pediremos a FUTUEx que lo lleve.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2017-12-28','(Pedro). Conversación con la DRa. Lola Díaz Quintero, de Medicina Interna del H. de Mérida. +++HABITACIÓN 223 (EXT.81051: control de Enfermería). En estos momentos está acompañada por su prima. +++Se le explica el papel de la Comisión en cuanto a inofrmación y decisiones a tomar y se le dejan vario teléfonos, fax y correo-e. Lo anota en la Hª clínica. +++ESTADO DE Dª ROSA: MUY GRAVE. +++++Neumonía bilateral., con posibilidad de requerir alimentación con sonda nasogástrica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2017-12-28','(Pedro)Llamada de José María (927-470022) y de su madre , Dª Marcela Simón Cepeda. +++REclama que le subamos 50€ la asignación. +++Dice a su madre que se ponga: "A ver si le pueden subir esos 50€ porque él se compra la comida ya hecha...Y lo que yo le digo, así es más cara que si va y hace la compra...Pero es que él no sabe..." SE le indica que en la proxima visita de Teresa le acompañe a hacer la compra y que se efuerce un poco con su preparación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2017-12-28','Iciar: Llama Maite, T.S. del centro penitenciario - 927 18 14 07-. A José María no le ha llegado a la cuenta del centro los 400 € que se le asignan mensualmente. Comprobado en su cuenta, a pesar de que la orden la hemos pasado para el día 25 de cada mes, al coincidir con festividad, la transferencia no se ha hecho hasta el día 27, y hoy 28 Maite asegura que no se ha recibido. Para que no vuelva a ocurrir cambiamos el día de la orden al 23 de cada mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2017-12-29','(Pedro) Conversación con Mª Victoria, Médica de Familia. +++Ayer estuvo hablndo con ella y la ve como siempre: con ese delirio de personalidad habitual en ella, pero que no le impide hacer una vida normal, sin moletar a nadie. No cree que haya motivo para ingreso. La perspectiva de ingreso en C. de Mayores considera que, quizá, en estos momentos sería más perjudicial que positivo. +++Hoy tiene que ir nuevamente a curarse y volverá a hablar con ella: le ruego nos envíe un informe en cuanto al seguimineto o no de su tratamiento, a la vez que intentar seguimiento en Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2017-12-29','Correo-e: en el día de hoy se nos informa que Concha continuará ingresada hasta el 2 o 3 de enero porque la neumonía requiere tratamiento intravenoso, la médica le dice que no pida el alta voluntaria, que permanezca en el hospital se le ha llevado dinero desde aquí, su asignación hasta el próximo lunes en principio le han hecho una placa esta mañana y esta tarde estiman que le harán otra han visto también que presenta el pericardio algo inflamado, irán confirmando con pruebas si se trata de una pequeña pericarditis comentan que esto no es importante, pero sí la importancia de la neumonía y de quedarse en el hospital mañana llamaremos otra vez y les comento lo que sea. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Gisela. +++Al parecer en el Infanta Cristina no saben que está tutelada. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª José, T. Soc. del Infanta Cristina (924-218075): +++Se informa de que Concepción está tutelada, a efectos de que solicite el alta voluntaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2017-12-29','Se envía a E.A.L.E.X por correo-e autorización para permanecer con sus tíos hasta el 07 de enero de 2018. Enviar también por correo ordinario una vez registrado de Salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='PARIENTE'and apellido2='LUCAS'),'2017-12-29','En relación con la herencia de los padres de Luisa, Donato Pariente Martín y Juliana Lucas Alcón, en su día solicitamos autorización para aceptar la herencia y nos la concedió el Juzgado de 1ª. Instancia e Instrucción nº 2, de Plasencia, así como autorización para vender el inmueble de la calle Calvo Sotelo, 16, de Villa del Campo. Calle que ahora se llama Pozó Morón, según aclaración que solicitamos al Ayto. del Villa del Campo. Enviamos esta documentación y toda la que teníamos a la notaría de Jiménez Mancha, en Plasencia, al oficial Juan José Fuentes (927411447) y se hizo un borrador de la escritura de aceptación de la herencia, pero no llegó a oficializarse. Mientras tanto, el hermano de Luisa, Pablo, también ha fallecido, teniendo una hija, Dolores (956253055, que al parecer vive en Cádiz y que la misma no está haciendo nada por agilizar los trámites de la herencia, ni de su padre ni de sus abuelos). Hemos recibido propuesta de compra de las dos fincas urbanas que hay en Calle Calvo Sotelo, 1 y 5, ahora Pozo Morón, de las que una de ellas ya derribamos por su estado de ruina, la casa y la otra, que es el almacén, está en las mismas circunstancias, pero no la hemos derribado. La oferta de compra de estos inmuebles es de 6.000 euros. Teniendo en cuenta que Luisa no tiene hijos, su situación económica es desahogada (actualmente en la rendición de cuentas tiene 14.589 euros), tiene todas sus necesidades cubiertas y que la heredera finalmente va a ser su sobrina Dolores, ya que Pablo no tuvo más hijos, no vamos a proceder a formalizar la herencia, debido a que de todo el inventario del borrador que se hizo en su día, desde notaría nos dicen que algunas de esas fincas ya se vendieron y aparecen de hecho a nombre de Pablo. Habría que actualizar todo el inventario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2018-01-02','iCIAR:Envío por correo A.R. a Aprosuba 3 la tarjeta de transporte subvencionado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='TREJO'and apellido2='COLLADO'),'2018-01-03','-NOS DAN LA RESOLUCION DE SU INGRESO EN R.M. FELIPE TRIGO DE VILLANUEVA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2018-01-05','ICIAR:Llama la prima de Dª Rosa, Dª Eulalia t/c 657487329,para informar que el domingo 7/1 marchan a Madrid pues tiene consulta médica y Rosa se quedará sola en el hospital. Dice que el estado de su prima sigue siendo muy grave.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2018-01-08','-AMALIA: TRAS RECIBIR LLAMADA DE ANABEL DEL EQUIPO DE VALORACION DEPENDENCIA , CONTACTO CON EL CSS PLASENCIA QUE ME INFORMA QUE EL DIA 22/12/2017 FUE DADO DE ALTA . NO TENEMOS DICHA COMUNICACION. LE PASO SU DIRECCION EN CACERES, SIGUE EN EL DOMCILIO CON LA MADRE Y LOS TF DE VARIOS FAMILIARES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2018-01-08','-AMALIA: LLAMA SU HNO . 677248077 , NOS DICE QUE SU HNO. ESTÁ TOMANDO MUCHISIMA MEDICACION EN EL CSS DE MERIDA DONDE SE ENCUENTRA QUE LE ESTÁ AFECTANDO A LOS RIÑONES. INFORMA DE LAS VARIAS FUGAS QUE HA TENIDO DEL CENTRO ( ASEGURA QUE VA A DROGARSE, ÉL TB FUE DROGODEPENDIENTE ) Y QUE LO CAMBIEMOS DE CENTRO. SE LE EXPLICA QUE NOSOTROS NO PRESCRIBIMOS MEDICACIÓN Y QUE DE MOMENTO Y HASTA QUE NO TENGA ALTA MÉDICA CONTINUARÁ ALLI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2018-01-08','-AMALIA: LLAMAN DESDE EL CENTRO PARA COMUNICAR QUE VA A SER HOSPITALIZADO. SE LE PONE ACOMPÑAMIENTO HOSP. PASARÁN LA FACTURA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2018-01-08','-AMALIA: HABLO CON ROSALBA SE VUELVE A PONER EL ACOMPAÑAM. HOSPIT. LAS MISMAS HORAS , HASTA EL REGRESO DE SU PRIMA. -PIDO EN DEPEND. RESOLUCION DE PRES. VINCULADA ME DAN UNA COPIA Y QUEDO PTE. DE LA ORIGINAL. PERCIBIRÁ 300€/ MES Y LE HAN ABONADO ATRASOS. -CON ESTA PRESTACION + SU PENSION PODEMOS MANTENERLA EN ROSALBA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2018-01-09','En relación con la ejecución hipotecaria del piso, la parte demandante ha pedido la posesión de la finca. Comentado el tema con Julián Cambero, el abogado que recurrió ante el TS, me indica que también ha recibido la misma Diligencia de Ordenación del Juzgado y que va a comentar el tema con Carmen Barquilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2018-01-09','Pablo, director del CRR de Cáceres, insiste con el tema del testamento de Agustin. Le indico que la sentencia no especifica nada al respecto y que lo que procede es acudir a Notaría para que el Notario designe a dos facultativos que valoren a Agustín, y determinen si puede o no hacer testamento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-01-09','Absuelven a Vanesa en el Juicio por delito leve nº 18/2017, del Juzgado de 1ª. Instancia e Instrucción nº 2, de Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2018-01-09','- NOS LLEGA CONTRATO DE SAD DE UNA EMPRESA LLAMADA EL BASTÓN QUE AL PARECER HA LLEGADO A CASA DE JOSEFA , NO SABEMOS SI LA EMPRESA LO HA ENVIADO ALLI O LO HA SOLICITADO SU CUÑADA, ME DECANTO POR LO PRIMERO . YO PEDI ESTE COTNRATO A LA EMPRESA CERUJOVI.. AL HABLAR POR TF. CON ELLOS PARA ANULARLO ME DOY CUENTA QUE AMBAS EMPRESAS SON LA MISMA . ANTE ESTA DESCONFIANZA PROCEDO A NO HACER CON NINGUNA DE ELLAS EL CONTRATO DE SAD Y SOLICITO A LA DELEGADA TUTELAR QUE ACOMPAÑADA POR JOSEFA Y SU CUÑADA SE PROCEDA A SOLICITAR OTRO A OTRA EMPRESA DISTINTA. NO ENVIO NADA A LAS EMPRESAS !!!! NO SE ENVIA NADA FIRMADO . SI QUIEREN QUE SE PONGAN EN CONTACTO CON NOSOTROS Y LES DIRÉ QUE NO SE VA A HACER NINGUN SERVICIO CON ELLOS. ( AMALIA)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2018-01-09','ICIAR: Ante la petición que hizo Abraham para que se subiera la asignación que se le da a su madre de aprox 450€/mes después de mirar su ficha con Alberto y con el visto bueno de la parte social, se le llama para confirmarle dicha asignación que se hará en dos pagos quincenales de 225€. A pesar de que fue él mismo quien sugerió esa cantidad dice ahora que cree que no va a ser suficiente. Le comunico que Pilar podrá pasar el día 15 por la sucursal a retirar el dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-01-10','ICIAR: Llama Mamen, T.S. 924 01 87 79 - Ext 20788, para información sobre cómo solicitar Pía, solicitar plaza en residencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTOR MANUEL'and edp.apellido1='DURAN'and apellido2='DALIA'),'2018-01-11','DESESTIMACION INCAPACIDAD El Jzdo. nº. 2 de Mérida, mediante Sentencia nº. 298/17, de 18 de diciembre, ha desestimado la propensión de incapacitación. Se archiva el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-01-15','Icíar. HAblo con Feafes Zafra al no haber podido localizar a Beatriz ni a Pilar de los pisos supervisados. Beatriz tenía que presentarse hoy en el juzgado de Zafra para una videoconferencia. Me informan desde Feafes que Pilar terminó su contrato y que Beatriz ha cambiado de nº de móvil. El nuevo es 643 600 503. No contesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-01-15','Iciar: Llama Maribel t/c 696 432 958, nos informa de que en coordinación con psiquiatría de la zona de Villanueva de la Serena, se está pensando een solicitar plaza para Yolanda en la UDAC de Plasencia debido a los problemas de conducta de Yolanda. Envian por correo electrónico la solicitud para que se tenga constancia en la Comisión, y para que les sea devuelto firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='GRUESO'and apellido2='JIMENEZ'),'2018-01-03','TRASLADO A HOSPITAL El 03/01/2018. "Se comunica a esa Comisión Tutelar de Adultos que el interno ..., ingresado en este Centro y tutelado por esa Comisión, será trasladado al Hospital de Mérida..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2018-01-15','Acudimos hoy al Juicio Verbal 684/2017, por el caso del accidente que tuvo Daniel, al salir de su casa con su bici y cruzarse una moto de Burger King. Él no acude inicialmente y no entra en sala. El juicio se celebra al estar nosotros representándole. Al salir me lo encuentro fuera con Katy, de Aprosuba 3. Me dicen que no sabían donde había que ir. Estamos a la espera de recibir la sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2017-01-12','ALTA HOSPITALARIA "Buenas tardes, se informa que esta tarde ha recibido alta hospitalaria Dña. Rosa Delgado Romero, volviendo a nuestro centro ROSALBA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-01-12','FECHAS CUMPLIMENTO CONDENA "En referencia a la sentencia que comunica que José Manuel Romero Mediavilla deberá cumplir arresto domiciliario, se ha comunicado al Juzgado de Mérida, con previa decisión por parte del CRR, que los días que cumplirá dicho arresto en este Centro serán os siguientes: miércoles, 07/02/2017; viernes, 09/02/2017; miércoles, 14/02/2017; viernes, 16/02/2017 y miércoles 21/02/2017. Dicha sentencia se les ha enviado a vosotros por fax el pasado 8 de enero a las 13.05 horas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-01-16','(Pedro) Llamada de D. Juan. +++Quiere que se le retire la curatela. +++Que le vea de nuevo el Juez, Fiscal y su abogado de oficio. +++Acudió ayer a la consulta de Asun para acceder a pisos supervisados: "No voy a ir a vivir con enfermos y entre drogadictos cuando yo soy una persona sana...Además, a mi me pusieron inyecciones de Nuremberg que me hicieron daño...Estve trabajando en el Edificio Inteligente de Madrid y paseaba por allí cuando el asesinato de los abogados laboralistas...Y se están violando mis derechos: es de dominio público hasta cuando hago mis necesidades como hombre..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-01-16','En relación con la ejecutoria 54/2017 dictada por la Audiencia Provincial sección 3, de Mérida, por la que condenan a Francisco Cuevas a una medida de intermaniento de 4 años en un centro socio-sanitario para el tratamiento de su patología, consultado con la misma si el centro debe ser de régimen abierto o cerrado, nos indican que han pasado nuestra consulta a su Señoría para que informe. En todo caso, el inicio de la medida de internamiento empieza a cumplirse desde el 21 de diciembre de 2017, fecha de la ejecutoria, que en el caso de ser en régimen abierto, ya la está cumpliendo. En el caso que sea en régimen cerrado, empezaría a cumplir la medida de 4 años desde el día que empiece a residir en el sociosanitario. En relación a este, él quería que el centro fuera el de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2018-01-16','(Pedro)Conversación con Juan Manuel, Médico de Familia de Dª Antonia (Consultorio Local de Cilleros: 927-512231). Alternativas de traslado para ingreso en Residencia "El Cuartillo" de Cáceres: +++Que la lleve su hijo Juan Carlos. +++Activar el 112. Considero menos traumático, quizá, para ella que sea su hijo el que lo realice: Juan Manuel hablará con él mañana (al aprecer llevan 15 días en los que no ha habido problemas) y en caso que no pueda o no quiera activará el 112. +++Dejo teléfonos de Ctaex y Fax. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Toni, de Futuex: opina que su hijo no va a acceder a llevarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-01-16','(Pedro)Conversación con Mª Ángeles (Psicóloga). +++ADAPTACIÓN: MUY BUENA, tanto con los compañeros como con los profesionales. Realmente se le ve CONTENTA. +++++Preparando su participación en los Jedex. El otro día había que verla cantando en el karaoke, sin parar de reirse. +++SALUD: Ya instaurado el implante como método anticonceptivo y acude regularmente a Neurología. Ya recuperada del parto. +++ROCÍO (HIJA): la nombra de vez en cuando, pero tiene muchas otras prioridades antes que esta.Ocasionalmente plantea que por qué no se la puede traer al centro y las cuidan a las dos a la vez. +++ANTONIO (PAREJA): MUY POCA RELACIÓN. No la llama (ni durante estas Navidades) y, si acaso le envía wasapp a los que ella no contesta. +++++Hace poco le envíó una fotografía suya con una niña de +/-18 meses en brazos (sobrina de Antonio), diciéndole que ya tenía con él a su hija. En el Centro le hicieron ver que no era su hija, ya que esta es un bebé todavía. Esto ENFADÓ MUCHO a Beatriz, quien ya no habla con Antonio desde entonces. +++ANDRÉS (PADRE). La ha llamado un par de veces durante las Navidades. +++ABUELA PATERNA (madre de Antonio): NINGÚN CONTACTO CON BEATRIZ NI CON EL CENTRO. +++MADRE DE BEATRIZ: últimamente no para de llamar al centro solicitando un certificado en el que se haga constar que su hija reside en el Centro y no con ella, a efectos de que Andalucía le siga pagando la pensión (al parecer ahora estyá en Huelva): como le ha dicho Mercedes, ñla T. Social de Aprosuba, que sea el servicio social que se lo pide quien se ponga en contacto con el Centro para ver qué quiere realmente. Informa a Mª Ángeles que en ningún caso hay por qué dar dato alguno de Beatriz sobre su residencia. +++++Durante estos CONTACTOS TELEFÓNICOS con el Centro NO HA PREGUNTADO NUNCA POR SU HIJA. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++REUNIÓN con Mara y la D.G. de Infancia y Familia el próximo día 18 de enero. +++Tema: medida de protección para Rocío (hija de Beatriz).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2018-01-16','Iciar: Hablo con Teresa Nogueira, T.S. de Novaforma,t/c 927 62 92 05. Mañana 18/1 acompañan a Álvaro al reconocimiento forense para recuperación del derecho de sufragio, además hemos enviado autorización para que puedan retirar una fe de vida y estado en el registro civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ELIAS'and edp.apellido1='MACHIO'and apellido2='FLORIDO'),'2018-01-16','Correo-e:D. Elias Machio Florido se encuentra ingresado en el Hospital Don Benito -Vvva por una infección respiratoria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-01-16','(Pedro)Conversación con Toni (Futuex). +++Llevarán a José María al Cadex junto con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2018-01-17','(Pedro) Visita de Isabel Valadés a las 9:00h, sin cita, como casi siempre, para pedir 50€ para las rebajas ("...Porque todo el mundo tiene derecho a ir de rebajas..."). +++NO SE LE AUTORIZA dicha extra porque sacó ayer los 110€ quincenales que ella misma solicitó. +++Manifiesta incialmente que se quedó sin dienro porque se encontró con una mujer a la que le debía dinero y le dió todo lo que suponía la deuda. En el transcurso de la conversación comenta que también compró la comida para estos 15 días pero que no le queda para las magdalenas que "...es lo único que como..." +++Su petición de 50€ ha ido rebajándose hasta los 5€ para compar magdalenas, "porque es lo único que como, reitera una y otra vez..." +++Habla con Alberto y se marcha a las 11:00 de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2018-01-17','(Pedro). Se recibe en la Comisión Fax del Dr. José Manuel indicando que no solamente D. Juan Carlos, hijo de Dª Antonia, no va a colaborar en el traslado de su madre sino que, además lo va a impedir hasta que n o vea la orden del mismo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Pilar, Enfermera. +++Dada la negativa del hijo se le envía la documentación para activar 112 por el Médico: Sentencia de incapacitación y aceptación del cargo, Auto del Juzgado con la autorización de ingreso involuntario, fecha de ingreso en la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2018-01-17','Iciar: Llamo a Inés t/c 617 968 787 después de ver el correo electrónico que nos envia la T.S. de Montijo. El pago de los recibos de comunidad que se adeudan no los hemos podido pagar por tener problemas con el BBVA a la hora de poner a Consolación en la libreta de Mª Antonia. Cuando se haya solucionado nos pondremos en contacto con ella. Además confirmamos que los recibos mensuales los vamos a pagar cada 6 meses (julio-enero).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2018-01-17','(Pedro) Llama Dª Antonia, madre de José Antonio. +++Ha recibido una carta de Hacienda en la que se comunica que no se ha realizado la Declaración del 2016. +++Le doy el número de fax para que nos envíe dicha notificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2018-01-17','(Pedro)SE autoriza la compra de una silla de bebé por importe de 50€, para el sobrino que va a nacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-01-15','(Pedro)Citación para videoconferencia en el Juzgado Decano de Zafra a las 9:30. +++NO se pudo celebrar la videoconferencia a la hora señalada porque Beatriz no se presesetó hasta las 10:00, y eso porque se le volvió a llamar antes de la hora señalada:"Pensaba que era a las 13:00 h y aún estoy en la cama". +++Se intentó la conexión a las 12:30 h pero no fue posible por problemas técnicos, por lo que queda PENDIENTE DE NUEVO SEÑALAMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-01-17','(Pedro). Se recibe por correo-e Informe de seguimiento del periodo de adaptación de Beatriz en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2018-01-17','(Pedro) Llamada de Sandra, Técnico PIA (24126). +++GRADO I. No da grado salvo para SAD. +++Dado que en el último Informe Social las condiciones en las que se encuentra en la residencia de Azabal son positivas no se considera la necesidad de modificación de las mismas salvo a propuesta, en su caso, del centro. +++Enviará No aceptación PIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2018-01-17','TRASLADO El 17/01/2018. "...el paciente José Dolores Vargas Chavero ha sido derivado al hospital de Mérida."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2018-01-18','Iciar: Llama Jesús Manuel para solictar un reintegro de 50€ porque su hijo se lo ha pedido. No informa para qué. Le comento, después de hablar con Alberto, que ante la situación en que se encuentra (embargo de la cuenta por Hacienda - multas) no va a ser posible. No acepta de buena gana la respuesta, y dice que se le está discriminando, que no puede atender a sus hijos que viven con él, algo que es incierta pues viven con la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2018-01-19','(Pedro). Conversación con Juan Manuel, Médico de Cilleros. +++Confirma que el lunes activará el 112 (está de guardia el domingo y quizá inicie el trámite este día). Hablará también con la Guardia Civil para que estén al tanto de la situación, dada la oposición frontal que Juan Carlos demostró el otro día. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Amparo, Directora de "El Cuartillo" (22140). Teléfono: 927-005280. Fax: 927-181081. +++Confrimo el traslado para el lunes 22 de enero, pero sin seguridad en la hora de llegada. Dejo el teléfono de Juan Manuel por si fuera necesario. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Teresa(Futuex). Toni no está. +++Confirmo traslado de Dª Antonia para que pueda ir Alicia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-01-18','Reunión en la D.G.Infancia y Familia. Presentes, Mercedes Leal, Jefa de Sección de Acog. Familiar, Mara Cendal, T. Social y Pedro Gracia, Jefe de Sección de CTAEx. +++Valorar la convenincia o no de las visitas madre-hija. +++Coordinar el tratamineto de la impugnación de la medida de acogimiento realizada por la abuela paterna. +++++Posibilidad de convocar reunión con Carmen Barquilla y la Fisclía de Menores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-01-19','(Pedro) Converscaión con MªAngeles, Psicóloga de Plena Inclusión (924-870293 y 924-870293). +++Se solicita, también por correo-e, Informe de valoración sobre la conveniencia o no de poner en marcha la medida de que Beatriz pueda ver a su hija. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada a Carmen Barquilla, Fiscal de Cáceres. No se encuentra en el Juzgado.','2');
